export class GLScheduledTransaction {
    glScheduledTransactionID : Number;
    glEventID : Number;
    leaseId : Number;
	dueByDate : String;
	amount : String;
	currency : String;
	vendor : String;
	status : String;
	name : String;
	account : String;
	accountCategory : String;
	accountType : String;
	frequency : string;
	country : string;
	buildingName : string;
	state : string;
	tenant : string;
	hierarchy : string;
	dueByYear : number;
	dueByMonth : string;
	leaseName : string;
	portfolio : string;

	constructor(glScheduledTransactionID,glEventID,leaseId,dueByDate,amount,currency,vendor,status,name,account, accountCategory, accountType, frequency, country, buildingName, state, tenant, hierarchy, dueByYear, dueByMonth, leaseName, portfolio) {
		this.glScheduledTransactionID = glScheduledTransactionID;
		this.glEventID = glEventID;		
		this.leaseId = leaseId;
		this.dueByDate = dueByDate;
		this.amount = amount;
		this.currency = currency;
		this.vendor = vendor;
		this.status = status;
		this.name = name;
		this.account = account;
		this.accountCategory = accountCategory;
		this.accountType = accountType;
		this.frequency = frequency;		
		this.country = country;
		this.buildingName = buildingName;
		this.state = state;
		this.tenant = tenant;
		this.hierarchy = hierarchy;
		this.dueByYear = dueByYear;
		this.dueByMonth = dueByMonth;
		this.leaseName = leaseName;
		this.portfolio = portfolio;
	}
}

